export interface NumberFormatOptions {
    locale?: string;
    useGrouping?: boolean;
    minFractionDigits?: number;
    maxFractionDigits?: number;
    mode?: "decimal" | "currency";
    currency?: string;
    prefix?: string;
    suffix?: string;
    min?: number;
    max?: number;
}

export function clampNumber(n: number, min?: number, max?: number) {
    if (Number.isNaN(n)) return n;
    if (min != null && n < min) return min;
    if (max != null && n > max) return max;
    return n;
}

export function parseLooseNumber(text: string): number | null {
    const cleaned = text.replace(/[^0-9.\-]/g, "");
    if (!cleaned || cleaned === "-" || cleaned === "." || cleaned === "-.") return null;
    const n = Number(cleaned);
    return Number.isFinite(n) ? n : null;
}

export function formatNumber(value: number | null | undefined, o: NumberFormatOptions): string {
    if (value == null || Number.isNaN(value)) return "";

    const v = clampNumber(value, o.min, o.max);

    const nf = new Intl.NumberFormat(o.locale, {
        style: o.mode === "currency" ? "currency" : "decimal",
        currency: o.mode === "currency" ? (o.currency ?? "USD") : undefined,
        useGrouping: o.useGrouping ?? true,
        minimumFractionDigits: o.minFractionDigits,
        maximumFractionDigits: o.maxFractionDigits,
    });

    let out = nf.format(v);
    if (o.prefix) out = `${o.prefix}${out}`;
    if (o.suffix) out = `${out}${o.suffix}`;
    return out;
}
